from pricing import calculate_order_total
from validator import validate_order

def process_all_orders(orders):
    results = []
    for order in orders:
        validated = validate_order(order)
        total = calculate_order_total(validated)
        results.append({
            "id": order["id"],
            "status": "complete",
            "total": total,
        })
    return results

